package com.bankapp;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class BankingAppActivity extends AppCompatActivity {
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String TRANSACTION_HISTORY_KEY = "transaction_history";
    
    private TextView balanceTextView;
    private Button depositButton;
    private Button withdrawButton;
    private Button transferButton;
    private ExecutorService executorService;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);
        
        initializeViews();
        setupClickListeners();
        loadAccountData();
        executorService = Executors.newSingleThreadExecutor();
    }
    
    private void initializeViews() {
        balanceTextView = findViewById(R.id.balanceTextView);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        transferButton = findViewById(R.id.transferButton);
    }
    
    private void setupClickListeners() {
        depositButton.setOnClickListener(v -> performTransaction("deposit"));
        withdrawButton.setOnClickListener(v -> performTransaction("withdraw"));
        transferButton.setOnClickListener(v -> performTransfer());
    }
    
    private void performTransaction(String type) {
        executorService.execute(() -> {
            SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
            String balanceStr = prefs.getString(BALANCE_KEY, "0.00");
            BigDecimal currentBalance = new BigDecimal(balanceStr);
            
            BigDecimal amount = new BigDecimal("100.00");
            BigDecimal newBalance;
            
            if ("deposit".equals(type)) {
                newBalance = currentBalance.add(amount);
                saveTransaction("Deposit", amount);
            } else {
                if (currentBalance.compareTo(amount) >= 0) {
                    newBalance = currentBalance.subtract(amount);
                    saveTransaction("Withdrawal", amount);
                } else {
                    runOnUiThread(() -> Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show());
                    return;
                }
            }
            
            SharedPreferences.Editor editor = prefs.edit();
            editor.putString(BALANCE_KEY, newBalance.setScale(2, RoundingMode.HALF_UP).toString());
            editor.apply();
            
            runOnUiThread(() -> {
                balanceTextView.setText(String.format("$%.2f", newBalance));
                Toast.makeText(this, type.substring(0, 1).toUpperCase() + type.substring(1) + " successful", 
                             Toast.LENGTH_SHORT).show();
            });
        });
    }
    
    private void performTransfer() {
        executorService.execute(() -> {
            SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
            String balanceStr = prefs.getString(BALANCE_KEY, "0.00");
            BigDecimal currentBalance = new BigDecimal(balanceStr);
            BigDecimal transferAmount = new BigDecimal("50.00");
            
            if (currentBalance.compareTo(transferAmount) >= 0) {
                BigDecimal newBalance = currentBalance.subtract(transferAmount);
                SharedPreferences.Editor editor = prefs.edit();
                editor.putString(BALANCE_KEY, newBalance.setScale(2, RoundingMode.HALF_UP).toString());
                editor.apply();
                
                runOnUiThread(() -> {
                    balanceTextView.setText(String.format("$%.2f", newBalance));
                    Toast.makeText(this, "Transfer successful", Toast.LENGTH_SHORT).show();
                });
            } else {
                runOnUiThread(() -> Toast.makeText(this, "Insufficient funds for transfer", Toast.LENGTH_SHORT).show());
            }
        });
    }
    
    private void saveTransaction(String type, BigDecimal amount) {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        String history = prefs.getString(TRANSACTION_HISTORY_KEY, "");
        String newEntry = String.format("%s: %s $%.2f\n", 
                                      java.time.LocalDateTime.now().toString(), 
                                      type, amount);
        SharedPreferences.Editor editor = prefs.edit();
        editor.putString(TRANSACTION_HISTORY_KEY, history + newEntry);
        editor.apply();
    }
    
    private void loadAccountData() {
        executorService.execute(() -> {
            SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
            String balanceStr = prefs.getString(BALANCE_KEY, "0.00");
            BigDecimal balance = new BigDecimal(balanceStr);
            
            runOnUiThread(() -> balanceTextView.setText(String.format("$%.2f", balance)));
        });
    }
    
    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (executorService != null) {
            executorService.shutdown();
        }
    }
}